package com.practice.visual.service;
import com.practice.visual.entity.DashboardScreen;import com.practice.visual.repository.DashboardScreenRepo;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;
@Service public class ScreenService { final DashboardScreenRepo repo; public ScreenService(DashboardScreenRepo repo){this.repo=repo;} @Transactional public DashboardScreen publish(Long id){DashboardScreen x=repo.findById(id).orElseThrow();x.published=true;x.status="PUBLISHED";x.configJson=filterTopology(x.configJson);return repo.save(x);} public String filterTopology(String json){ if(json==null)return null; return json.replaceAll(",?\\{[^{}]*\\\"type\\\"\\s*:\\s*\\\"topology\\\"[^{}]*\\}","").replace("[,", "[").replace(",]", "]"); } }
